// ── GLSL Ocean Shader ──
(function(){
  const cv=document.getElementById('ocean-canvas');
  const gl=cv.getContext('webgl')||cv.getContext('experimental-webgl');
  if(!gl)return;
  function rsz(){cv.width=innerWidth;cv.height=innerHeight;gl.viewport(0,0,cv.width,cv.height);}
  rsz();window.addEventListener('resize',rsz);
  const vs=`attribute vec2 a;void main(){gl_Position=vec4(a,0,1);}`;
  const fs=`precision mediump float;
  uniform float T;uniform vec2 R;uniform float S;uniform vec2 M;uniform vec3 uBG1;uniform vec3 uBG2;
  float h(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453);}
  float n(vec2 p){vec2 i=floor(p),f=fract(p),u=f*f*(3.-2.*f);return mix(mix(h(i),h(i+vec2(1,0)),u.x),mix(h(i+vec2(0,1)),h(i+vec2(1,1)),u.x),u.y);}
  float fbm(vec2 p){float v=0.,a=.5;for(int i=0;i<6;i++){v+=a*n(p);p=p*2.1+vec2(1.7,9.2);a*=.5;}return v;}
  void main(){
    vec2 uv=gl_FragCoord.xy/R;float asp=R.x/R.y;uv.x*=asp;
    float t=T*.18,sc=S;float dep=clamp(1.-uv.y+sc*.3,0.,1.);
    vec3 bg=mix(uBG1,uBG2,dep);
    vec2 p=uv*2.5+vec2(-t*.4,t*.15);
    float w=fbm(p+vec2(t*.3,0))*.5+fbm(p*1.8-vec2(t*.2,t*.1))*.3+fbm(p*.6+vec2(0,t*.25))*.2;
    vec2 cp=uv*6.+vec2(t*.5,-t*.3);float ca=pow(fbm(cp)*fbm(cp*1.3+vec2(3.1,1.7)),2.5)*.8;
    vec2 mv=M;mv.x*=asp;float md=distance(uv,mv);float rip=sin(md*40.-t*8.)*exp(-md*6.)*.06;
    float gl2=0.;for(int i=0;i<5;i++){float fi=float(i);float y=fract(.15*fi+t*(.08+fi*.02)-sc*.1);gl2+=smoothstep(.005,0.,abs(uv.y-y))*smoothstep(1.,.3,abs(fract(uv.x*.3+t*.05*(1.+fi*.3))-.5)*2.)*.4;}
    vec3 c=bg+vec3(.18,.62,.88)*(w*.04+ca*.08+rip)+vec3(.96,.65,.14)*gl2*(1.-dep*.5);
    float vi=1.-smoothstep(.4,1.2,length(uv-vec2(asp*.5,.5)));
    gl_FragColor=vec4(c*(vi*.06+.94),1.);}`;
  function cs(tp,src){const s=gl.createShader(tp);gl.shaderSource(s,src);gl.compileShader(s);return s;}
  const pg=gl.createProgram();
  gl.attachShader(pg,cs(gl.VERTEX_SHADER,vs));gl.attachShader(pg,cs(gl.FRAGMENT_SHADER,fs));
  gl.linkProgram(pg);gl.useProgram(pg);
  const bf=gl.createBuffer();gl.bindBuffer(gl.ARRAY_BUFFER,bf);
  gl.bufferData(gl.ARRAY_BUFFER,new Float32Array([-1,-1,1,-1,-1,1,1,1]),gl.STATIC_DRAW);
  const al=gl.getAttribLocation(pg,'a');gl.enableVertexAttribArray(al);gl.vertexAttribPointer(al,2,gl.FLOAT,false,0,0);
  const uT=gl.getUniformLocation(pg,'T'),uR=gl.getUniformLocation(pg,'R'),uS=gl.getUniformLocation(pg,'S'),uM=gl.getUniformLocation(pg,'M'),uBG1=gl.getUniformLocation(pg,'uBG1'),uBG2=gl.getUniformLocation(pg,'uBG2');
  let mx=.5,my=.5;
  document.addEventListener('mousemove',e=>{mx=e.clientX/innerWidth;my=1-e.clientY/innerHeight;});
  const t0=performance.now();
  (function(){
  // LIGHT THEME: Hero=ライトスカイ → Concept=ソフトブルー → History=ウォームクリーム → Tech=ペールラベンダー → Finale=アイボリー
  // BG1=画面上端色, BG2=画面下端色
  const STOPS1=[ // 画面上端
    [0.00, 0.920,0.960,0.980],  // Hero     : 明るいスカイブルー白
    [0.12, 0.840,0.920,0.960],  // Hero→概念: 薄スカイブルー
    [0.25, 0.760,0.880,0.950],  // Concept  : ソフトブルー
    [0.35, 0.900,0.920,0.960],  // 移行      : ライトブルーグレー
    [0.50, 0.980,0.950,0.900],  // History  : ウォームアイボリー
    [0.62, 0.960,0.930,0.860],  // 移行      : ゴールドクリーム
    [0.72, 0.860,0.910,0.960],  // Tech     : ペールスカイ
    [0.85, 0.900,0.940,0.980],  // Tech深化 : ライトブルー
    [0.93, 0.960,0.960,0.975],  // 移行      : ほぼ白
    [1.00, 0.980,0.965,0.945],  // Finale   : ウォームアイボリー
  ];
  const STOPS2=[ // 画面下端（上端より少し深い同系色）
    [0.00, 0.780,0.900,0.960],
    [0.12, 0.700,0.840,0.930],
    [0.25, 0.640,0.800,0.920],
    [0.35, 0.790,0.840,0.910],
    [0.50, 0.940,0.880,0.780],
    [0.62, 0.920,0.850,0.730],
    [0.72, 0.760,0.840,0.930],
    [0.85, 0.820,0.870,0.950],
    [0.93, 0.920,0.920,0.940],
    [1.00, 0.950,0.910,0.870],
  ];
  function lerpS(stops,s){
    let a=stops[0],b=stops[stops.length-1];
    for(let i=0;i<stops.length-1;i++){if(s>=stops[i][0]&&s<=stops[i+1][0]){a=stops[i];b=stops[i+1];break;}}
    const t=b[0]===a[0]?0:(s-a[0])/(b[0]-a[0]);
    return[a[1]+(b[1]-a[1])*t, a[2]+(b[2]-a[2])*t, a[3]+(b[3]-a[3])*t];
  }
  let scSmooth=0;
  (function lp(){
    const t=(performance.now()-t0)/1000,sc=scrollY/(document.body.scrollHeight-innerHeight||1);
    scSmooth+=(sc-scSmooth)*0.055; // 少し速めに反応
    const c1=lerpS(STOPS1,scSmooth);
    const c2=lerpS(STOPS2,scSmooth);
    gl.uniform1f(uT,t);gl.uniform2f(uR,cv.width,cv.height);gl.uniform1f(uS,sc);gl.uniform2f(uM,mx,my);
    gl.uniform3f(uBG1,c1[0],c1[1],c1[2]);
    gl.uniform3f(uBG2,c2[0],c2[1],c2[2]);
    gl.drawArrays(gl.TRIANGLE_STRIP,0,4);requestAnimationFrame(lp);
  })();
})();
})();

