// source replaced with scene.glb (user attached)
let whaleModel=null;
let mixer=null;
let whaleRig=null;
let whaleHasNativeAnimation=false;
let whaleFrontRevealStart=0;
const whaleFrontFaceYaw=-Math.PI*0.085; // 実見え基準で少し右寄りに補正
const whaleFrontHoldSec=1.32; // 最初は正面をしっかり見せる
const whaleFrontEaseOutSec=1.22; // その後ゆっくり通常の泳ぎへ戻す
const clk=new THREE.Clock();

function captureSwimRig(root){
  const bonesByName={};
  root.traverse(obj=>{ if(obj.isBone && obj.name) bonesByName[obj.name]=obj; });
  const get=name=>bonesByName[name]||null;
  const rig={
    spine:['Spine1','Spine2','Spine3','Spine4'].map(get).filter(Boolean),
    tail:get('Tail'),
    flipperL:['TopFlipperL','MidFlipperL','BottomFlipperL'].map(get).filter(Boolean),
    flipperR:['TopFlipperR','MidFlipperR','BottomFlipperR'].map(get).filter(Boolean),
    head:get('Head'),
    base:new Map(),
  };
  [...rig.spine, rig.tail, ...rig.flipperL, ...rig.flipperR, rig.head].filter(Boolean).forEach(bone=>{
    rig.base.set(bone.uuid,{x:bone.rotation.x,y:bone.rotation.y,z:bone.rotation.z});
  });
  rig.hasBones = rig.base.size > 0;
  return rig;
}

function applyProceduralSwim(rig, t, intensity=1, speed=1, phase=0){
  if(!rig || !rig.hasBones) return;
  const swimT = t * (2.35 * speed) + phase;
  rig.spine.forEach((bone,i)=>{
    const base = rig.base.get(bone.uuid);
    const wave = Math.sin(swimT - i * 0.72);
    bone.rotation.y = base.y + wave * (0.024 + i * 0.016) * intensity;
    bone.rotation.z = base.z + wave * (0.007 + i * 0.007) * intensity;
  });
  if(rig.tail){
    const base = rig.base.get(rig.tail.uuid);
    const tailWave = Math.sin(swimT - 3.05);
    rig.tail.rotation.y = base.y + tailWave * 0.16 * intensity;
    rig.tail.rotation.z = base.z + tailWave * 0.055 * intensity;
  }
  rig.flipperL.forEach((bone,i)=>{
    const base = rig.base.get(bone.uuid);
    const flap = Math.sin(swimT * 0.92 + 0.9 - i * 0.48);
    bone.rotation.z = base.z + flap * (0.045 - i * 0.009) * intensity;
  });
  rig.flipperR.forEach((bone,i)=>{
    const base = rig.base.get(bone.uuid);
    const flap = Math.sin(swimT * 0.92 + 0.9 - i * 0.48);
    bone.rotation.z = base.z - flap * (0.045 - i * 0.009) * intensity;
  });
  if(rig.head){
    const base = rig.base.get(rig.head.uuid);
    rig.head.rotation.y = base.y - Math.sin(swimT - 0.45) * 0.012 * intensity;
    rig.head.rotation.z = base.z - Math.sin(swimT - 0.45) * 0.005 * intensity;
  }
}

function applyTailAccent(rig, t, intensity=1, speed=1, phase=0){
  if(!rig || !rig.tail) return;
  const sway = Math.sin(t * (3.85 * speed) + phase);
  rig.tail.rotation.y += sway * 0.085 * intensity;
  rig.tail.rotation.z += sway * 0.032 * intensity;
  const lastSpine = rig.spine && rig.spine.length ? rig.spine[rig.spine.length - 1] : null;
  if(lastSpine){
    lastSpine.rotation.y += sway * 0.028 * intensity;
    lastSpine.rotation.z += sway * 0.011 * intensity;
  }
}

(function loadWhale(){
  const b64="";
  const bin=atob(b64);
  const buf=new ArrayBuffer(bin.length);
  const view=new Uint8Array(buf);
  for(let i=0;i<bin.length;i++)view[i]=bin.charCodeAt(i);
  window._whaleb64 = buf.slice(0); // 仲間のクジラ用にArrayBufferをグローバル保存

  const loader=new THREE.GLTFLoader();
  loader.parse(buf,'',gltf=>{
    whaleModel=gltf.scene;

    // マテリアル調整：明るく・暖かいトーンに
    whaleModel.traverse(child=>{
      if(child.isMesh){
        child.castShadow=false;
        // 元の色を明るく・ウォームトーンに調整
        if(child.material){
          const m=child.material;
          if(m.color){
            const c=m.color;
            // 元の色を暖色系にシフト（オレンジ/アンバー）
            const orig_r=c.r, orig_g=c.g, orig_b=c.b;
            // 元の色をやわらかなゴールド〜ピーチへ寄せつつ白っぽさを残す
            c.r=Math.min(orig_r*1.02+0.12,1);
            c.g=Math.min(orig_g*0.96+0.10,1);
            c.b=Math.min(orig_b*0.82+0.06,1);
          }
          if(m.emissive){ m.emissive.set(0xeeb67a); m.emissiveIntensity=0.08; }
          m.roughness=0.74;
          m.metalness=0.03;
        }
      }
    });

    // スケール・位置調整
    const box=new THREE.Box3().setFromObject(whaleModel);
    const size=box.getSize(new THREE.Vector3());
    const scale=3.5/Math.max(size.x,size.y,size.z);
    whaleModel.scale.setScalar(scale);
    const center=box.getCenter(new THREE.Vector3());
    whaleModel.position.sub(center.multiplyScalar(scale));
    whaleModel.rotation.y=whaleFrontFaceYaw; // 初期から正面寄せ
    whaleModel.rotation.z=0;

    scene.add(whaleModel);
    whaleRig=captureSwimRig(whaleModel);
    whaleHasNativeAnimation=!!(gltf.animations && gltf.animations.length>0);

    // アニメーション（Swim）
    if(whaleHasNativeAnimation){
      mixer=new THREE.AnimationMixer(whaleModel);
      const clip=gltf.animations[0];
      const action=mixer.clipAction(clip);
      action.setEffectiveTimeScale(0.62);
      action.play();
    }

  },err=>console.error('GLB load error:',err));
})();

// ── 背景色スクロール変化（明るいグラデーション）──
let scBg=0;
const BG=[
  {s:0.00,r:246,g:240,b:227}, // hero     : アイボリー
  {s:0.25,r:253,g:251,b:247}, // concept  : 柔らかな白
  {s:0.50,r:232,g:246,b:251}, // history  : 淡いブルー
  {s:0.75,r:216,g:240,b:247}, // tech     : 透明感あるシアン
  {s:1.00,r:244,g:238,b:227}, // finale   : 温かいクリーム
];
function bgColor(s){
  let a=BG[0],b=BG[BG.length-1];
  for(let i=0;i<BG.length-1;i++){if(s>=BG[i].s&&s<=BG[i+1].s){a=BG[i];b=BG[i+1];break;}}
  const t=b.s===a.s?0:(s-a.s)/(b.s-a.s);
  return`rgb(${Math.round(a.r+(b.r-a.r)*t)},${Math.round(a.g+(b.g-a.g)*t)},${Math.round(a.b+(b.b-a.b)*t)})`;
}


