// ── 1頭スポーン ───────────────────────────────────────
function _spawnCompanionWhale(cfg) {
  if (!window._whaleb64) return;

  // ── ランダムパラメータを生成（毎スポーンごとに異なる）──
  const rnd = () => Math.random();
  cfg = Object.assign({}, cfg, {
    vx        : 2.5  + rnd() * 4.0,
    scaleFac  : 0.38 + rnd() * 0.50,
    z         : -1.0 - rnd() * 3.5,
    initY     : (rnd() - 0.5) * 6.4,         // 縦位置 -3.2〜+3.2（画面全体に散らばす）
    yAmp      : 0.20 + rnd() * 0.70,         // 縦揺れ幅 大きめ
    yFreq     : 0.18 + rnd() * 0.25,
    maxOpacity: 0.58 + rnd() * 0.24,
    hue: _rainbowHue / 360,
  });
  _rainbowHue = (_rainbowHue + 51) % 360;    // 次の頭は51°ずれた色相

  const cBuf = window._whaleb64.slice(0); // ArrayBufferをコピーして使用

  const loader = new THREE.GLTFLoader();
  loader.parse(cBuf, '', gltf => {
    const model = gltf.scene;

    // マテリアル：虹色 HSL + emissive 発光で視認性を確保
    const _initCol = new THREE.Color().setHSL(cfg.hue, 1.0, 0.58);
    const _initEmi = new THREE.Color().setHSL(cfg.hue, 1.0, 0.28);
    model.traverse(child => {
      if (child.isMesh) {
        child.castShadow = false;
        const m = new THREE.MeshStandardMaterial({
          color             : _initCol.clone(),
          emissive          : _initEmi.clone(),
          emissiveIntensity : 0.62,
          roughness         : 0.88,
          metalness         : 0.02,
          transparent       : true,
          opacity           : 0,
          depthWrite        : false,
          side              : THREE.FrontSide,
        });
        m.needsUpdate = true;
        child.material = m;
      }
    });

    // スケール
    const box   = new THREE.Box3().setFromObject(model);
    const size  = box.getSize(new THREE.Vector3());
    const scale = (3.5 * cfg.scaleFac) / Math.max(size.x, size.y, size.z);
    model.scale.setScalar(scale);

    // 初期位置：左外 (x=-15)、initY で高さを調整
    model.position.set(-15, cfg.initY, cfg.z);

    // 右向き（+x方向）: rotation.y = -PI/2 付近
    model.rotation.y = Math.PI * 0.52 + (Math.random() - 0.5) * 0.08;
    model.rotation.z = 0;

    scene.add(model);

    // スケルトンアニメーション
    let cMixer = null;
    if (gltf.animations && gltf.animations.length > 0) {
      cMixer = new THREE.AnimationMixer(model);
      const clip   = gltf.animations[0];
      const action = cMixer.clipAction(clip);
      action.setEffectiveTimeScale(0.66 + Math.random() * 0.18);
      action.play();
    }

    model.position.set(-15, cfg.initY, cfg.z);  // ロード完了後も位置を保証

    const swimRig = captureSwimRig(model);
    const hasNativeAnimation = !!(gltf.animations && gltf.animations.length > 0);

    companionWhales.push({
      model, mixer: cMixer, swimRig, hasNativeAnimation,
      x: -15, y: cfg.initY, z: cfg.z, initY: cfg.initY,
      vx: cfg.vx, yAmp: cfg.yAmp, yFreq: cfg.yFreq,
      tLocal: 0, opacity: 0, maxOpacity: cfg.maxOpacity,
      hue: cfg.hue,                          // 虹色: 現在の色相 (0〜1)
      swimPhase: Math.random() * Math.PI * 2,
      swimSpeed: 1.05 + Math.random() * 0.28,
      state: 'fadein',
    });

    console.log('[CompanionWhale] spawned +1, total:', companionWhales.length);
  }, err => console.error('[CompanionWhale] load error:', err));
}

// ── クリア ────────────────────────────────────────────
function _clearCompanionWhales() {
  companionWhales.forEach(cw => scene.remove(cw.model));
  companionWhales.length = 0;
  _spawnDone = false;
}

// ── フレーム更新（animate() から呼ぶ）────────────────
window._updateCompanions = function(delta) {
  for (let i = companionWhales.length - 1; i >= 0; i--) {
    const cw = companionWhales[i];
    cw.tLocal += delta;

    if (cw.mixer) cw.mixer.update(delta);
    if (!cw.hasNativeAnimation) applyProceduralSwim(cw.swimRig, cw.tLocal, 0.88, cw.swimSpeed, cw.swimPhase);
    if (cw.hasNativeAnimation) applyTailAccent(cw.swimRig, cw.tLocal, 0.78, 1.12 * cw.swimSpeed, cw.swimPhase);

    // X 移動（左→右）
    cw.x += cw.vx * delta;

    // Y 揺れ（控えめに：大群のキビキビ感を出す）
    cw.y = cw.initY + Math.sin(cw.tLocal * cw.yFreq * Math.PI * 2) * cw.yAmp;
    cw.model.position.y = cw.y;

    // フェードイン：速攻で見えるように
    if (cw.state === 'fadein') {
      cw.opacity = Math.min(cw.opacity + delta * 2.0, cw.maxOpacity);
      if (cw.opacity >= cw.maxOpacity * 0.99) cw.state = 'cruise';
    }

    // フェードアウト：x > +8 (画面右端付近)
    if (cw.state === 'cruise' && cw.x > 8) cw.state = 'fadeout';

    if (cw.state === 'fadeout') {
      cw.opacity = Math.max(cw.opacity - delta * 1.0, 0);
      if (cw.opacity <= 0.001) {
        scene.remove(cw.model);
        companionWhales.splice(i, 1);
        // 全頭が通過 & セクションまだ表示中 → ループ再スポーン
        if (companionWhales.length === 0 && _spawnDone && _historyVisible) {
          console.log('[CompanionWhale] all passed → re-spawn flock');
          _spawnDone = false;
          _loopTimers.forEach(t => clearTimeout(t));
          _loopTimers = [];
          COMPANION_CONFIGS.forEach(cfg => {
            const t = setTimeout(() => { if (_historyVisible) _spawnCompanionWhale(cfg); }, cfg.delay);
            _loopTimers.push(t);
          });
          const lastD = Math.max(...COMPANION_CONFIGS.map(c => c.delay));
          const td = setTimeout(() => { _spawnDone = true; }, lastD + 200);
          _loopTimers.push(td);
        }
        continue;
      }
    }

    // 位置・回転を反映
    cw.model.position.x = cw.x;
    cw.model.position.z = cw.z;
    // Z軸揺れ（体のうねり）
    cw.model.rotation.z = -Math.sin(cw.tLocal * cw.yFreq * Math.PI * 2) * 0.022;

    // 虹色シフト: 約20秒で1周（delta * 0.05 = 20s/cycle）
    cw.hue = (cw.hue + delta * 0.05) % 1.0;
    // 色相・透明度を全メッシュに適用
    cw.model.traverse(child => {
      if (child.isMesh && child.material) {
        child.material.color.setHSL(cw.hue, 0.92, 0.62);
        child.material.emissive.setHSL(cw.hue, 0.62, 0.24);
        child.material.emissiveIntensity = 0.42;
        child.material.opacity = cw.opacity * 0.94;
      }
    });
  }
};

// ── initY を push データに保存し直す（Y揺れ基準用）────
// (上の _updateCompanions で cw.initY を参照するため push 時に追加)
const _origSpawn = _spawnCompanionWhale;
// → companionWhales.push 内で initY を持たせる修正は下部で対処済み

// ── IntersectionObserver で #history-section を監視 ──
(function setupHistoryObserver() {
  const historyEl = document.getElementById('history-section');
  if (!historyEl) return;

  let _spawnTimers = [];

  const obs = new IntersectionObserver(entries => {
    entries.forEach(entry => {
      if (entry.isIntersecting && !_historyVisible) {
        _historyVisible = true;
        console.log('[CompanionWhale] history-section entered → spawn flock');

        _clearCompanionWhales();
        _spawnTimers.forEach(t => clearTimeout(t));
        _spawnTimers = [];
        _spawnDone   = false;

        // 7頭を時差スポーン
        COMPANION_CONFIGS.forEach(cfg => {
          const t = setTimeout(() => _spawnCompanionWhale(cfg), cfg.delay);
          _spawnTimers.push(t);
        });

        // 最後のdelayが終わったら _spawnDone = true
        const lastDelay = Math.max(...COMPANION_CONFIGS.map(c => c.delay));
        setTimeout(() => { _spawnDone = true; }, lastDelay + 200);

      } else if (!entry.isIntersecting && _historyVisible) {
        _historyVisible = false;
        console.log('[CompanionWhale] history-section left');
        // ループ再スポーンタイマーも全キャンセル
        _loopTimers.forEach(t => clearTimeout(t));
        _loopTimers = [];
        _spawnDone = false;
        companionWhales.forEach(cw => {
          if (cw.state !== 'fadeout') cw.state = 'fadeout';
        });
      }
    });
  }, { threshold: 0.2, rootMargin: '-12% 0px -12% 0px' });

  obs.observe(historyEl);
  console.log('[CompanionWhale] observer set on #history-section');
})();

// ── アニメーションループ ──
function animate(){
  requestAnimationFrame(animate);
  // getDeltaを先に呼ぶことで正確なフレーム時間を取得
  const delta=clk.getDelta();
  const t=clk.elapsedTime;
  const sc=scrollY/(document.body.scrollHeight-innerHeight||1);

  // mixerをフレーム時間ベースで更新（骨格アニメーションもゆっくり）
  if(mixer) mixer.update(delta);
  if(whaleRig && !whaleHasNativeAnimation) applyProceduralSwim(whaleRig, t, 1.0, 1.0, 0);
  if(whaleRig && whaleHasNativeAnimation) applyTailAccent(whaleRig, t, 1.0, 1.18, 0);

  if(whaleModel){
    // マウス追従をlerpでなめらかに
    mXS+=(mX-mXS)*0.04;
    mYS+=(mY-mYS)*0.04;
    // 最初は正面寄せで見せ、少し保ってから通常の泳ぎへ戻す
    const revealElapsed=Math.max(0,t-whaleFrontRevealStart);
    let frontFocus=1;
    if(revealElapsed>whaleFrontHoldSec){
      const p=Math.min(1,(revealElapsed-whaleFrontHoldSec)/whaleFrontEaseOutSec);
      frontFocus=1-(p*p*(3-2*p));
    }
    const swimY=Math.sin(t*0.30)*0.28;
    const swimRotZ=Math.sin(t*0.30)*0.024;
    const swimRotY=Math.PI*0.05+Math.sin(t*0.16)*0.05+sc*1.2;
    const swimX=Math.sin(t*0.20)*0.30+mXS*0.35;
    const frontY=swimY*0.06;
    const frontX=swimX*0.08;

    whaleModel.position.y=swimY+(frontY-swimY)*frontFocus;
    whaleModel.rotation.z=swimRotZ*(1-frontFocus);
    whaleModel.rotation.y=swimRotY+(whaleFrontFaceYaw-swimRotY)*frontFocus;
    whaleModel.position.x=swimX+(frontX-swimX)*frontFocus;
    whaleModel.position.y+=mYS*-0.18*(1-frontFocus*0.82);
  }

  // カメラスクロール
  cam.position.z=9-sc*4.0;
  cam.position.y=0.5+sc*-1.5;

  // リング
  ring.rotation.z=t*0.05;
  ringMat.opacity=0.10+Math.sin(t*0.9)*0.04;

  // 背景色をスクロール位置に応じてなめらかに変化
  // 背景色はシェーダーuniform(uBG1/uBG2)で制御

  // 仲間クジラの更新
  if (typeof window._updateCompanions === 'function') window._updateCompanions(delta);

  renderer.render(scene,cam);
}
animate();

// ── ローディング演出 & 非表示 ──
(function(){
  const GROUPS = [
    { byte:'01001011', letter:'K' },
    { byte:'01010101', letter:'U' },
    { byte:'01001010', letter:'J' },
    { byte:'01001001', letter:'I' },
    { byte:'01010010', letter:'R' },
    { byte:'01000001', letter:'A' },
  ];

  const randomByte = () => Array.from({length:8}, () => Math.random() < 0.5 ? '1' : '0').join('');
  const easeOutCubic = p => 1 - Math.pow(1 - p, 3);
  const lerp = (a,b,t) => a + (b - a) * t;
  const setImp = (el, prop, value) => { if(el) el.style.setProperty(prop, value, 'important'); };
  const clearImp = (el, prop) => { if(el) el.style.removeProperty(prop); };

  function animateFocus(el, opts){
    if(!el) return;
    const {
      duration = 1000,
      delay = 0,
      fromOpacity = 0,
      toOpacity = 1,
      fromScale = 1,
      toScale = 1,
      fromY = 0,
      toY = 0,
      fromBlur = 0,
      toBlur = 0,
      fromBrightness,
      toBrightness,
      fromSaturate,
      toSaturate,
      keepAnimation = 'none',
      clearFilter = true,
      clearTransform = true,
      clearOpacity = true,
    } = opts || {};

    setImp(el, 'animation', keepAnimation === 'none' ? 'none' : keepAnimation);
    const startAt = performance.now() + delay;
    const step = (now) => {
      if(now < startAt){
        requestAnimationFrame(step);
        return;
      }
      const p = Math.min(1, (now - startAt) / duration);
      const e = easeOutCubic(p);
      const opacity = lerp(fromOpacity, toOpacity, e);
      const scale = lerp(fromScale, toScale, e);
      const y = lerp(fromY, toY, e);
      const blur = lerp(fromBlur, toBlur, e);
      const filterParts = [`blur(${blur.toFixed(2)}px)`];
      if(fromBrightness !== undefined || toBrightness !== undefined){
        filterParts.push(`brightness(${lerp(fromBrightness ?? 1, toBrightness ?? 1, e).toFixed(3)})`);
      }
      if(fromSaturate !== undefined || toSaturate !== undefined){
        filterParts.push(`saturate(${lerp(fromSaturate ?? 1, toSaturate ?? 1, e).toFixed(3)})`);
      }
      setImp(el, 'opacity', opacity.toFixed(3));
      setImp(el, 'transform', `translateY(${y.toFixed(2)}px) scale(${scale.toFixed(4)})`);
      setImp(el, 'filter', filterParts.join(' '));
      if(p < 1){
        requestAnimationFrame(step);
        return;
      }
      if(clearOpacity) clearImp(el, 'opacity');
      if(clearTransform) clearImp(el, 'transform');
      if(clearFilter) clearImp(el, 'filter');
    };
    requestAnimationFrame(step);
  }

  function runYearBlast(numEl, ld){
    if(!numEl) return;
    const loaderLabel = document.getElementById('ld-decode-label');
    const loaderBarWrap = document.querySelector('.ld-bar-wrap');
    numEl.classList.add('year-blast-active');
    numEl.classList.remove('year-glow');
    numEl.classList.remove('invert-white');
    numEl.classList.remove('flash');
    if(loaderLabel){
      loaderLabel.style.opacity = '0';
      loaderLabel.style.transform = 'scale(.98)';
      loaderLabel.style.filter = 'blur(8px)';
    }
    if(loaderBarWrap){
      loaderBarWrap.style.opacity = '0';
      loaderBarWrap.style.transform = 'scaleX(.96)';
      loaderBarWrap.style.filter = 'blur(6px)';
    }
    setImp(numEl, 'transform-origin', 'center center');
    setImp(numEl, 'will-change', 'transform, opacity, filter');
    setImp(numEl, 'transition', 'none');
    setImp(numEl, 'animation', 'none');
    setImp(numEl, 'backface-visibility', 'hidden');
    const duration = 1500;
    const holdRatio = 0.30;
    const startAt = performance.now();
    let finalized = false;
    const step = (now) => {
      const p = Math.min(1, (now - startAt) / duration);
      let scale;
      let blur;
      let opacity;
      if(p < holdRatio){
        const holdP = p / holdRatio;
        scale = lerp(1, 1.02, holdP);
        blur = 0;
        opacity = 1;
      }else{
        const rushP = (p - holdRatio) / (1 - holdRatio);
        const e = easeOutCubic(rushP);
        scale = lerp(1.02, 6.1, e);
        blur = rushP < 0.34 ? 0 : lerp(0, 11, (rushP - 0.34) / 0.66);
        opacity = rushP < 0.84 ? 1 : lerp(1, 0.88, (rushP - 0.84) / 0.16);
      }
      setImp(numEl, 'transform', `scale(${scale.toFixed(4)})`);
      setImp(numEl, 'opacity', opacity.toFixed(3));
      setImp(numEl, 'filter', `blur(${Math.max(0, blur).toFixed(2)}px) drop-shadow(0 0 10px rgba(255,255,255,.14))`);
      if(p < 1){
        requestAnimationFrame(step);
        return;
      }
      if(finalized) return;
      finalized = true;
      numEl.classList.add('invert-white');
      numEl.classList.add('flash');
      setTimeout(()=>{ if(ld) ld.classList.add('whiteout'); }, 60);
    };
    requestAnimationFrame(step);
  }

  function runWorldRevealFocus(){
    animateFocus(document.getElementById('ocean-canvas'), {
      duration: 2250,
      fromOpacity: .68, toOpacity: 1,
      fromScale: 1.04, toScale: 1,
      fromBlur: 8, toBlur: 0,
      fromBrightness: .985, toBrightness: 1,
      fromSaturate: .985, toSaturate: 1,
      keepAnimation: 'none', clearFilter: true, clearTransform: true, clearOpacity: true,
    });
    animateFocus(document.getElementById('three-wrap'), {
      duration: 2250,
      fromOpacity: .72, toOpacity: 1,
      fromScale: 1.04, toScale: 1,
      fromBlur: 8, toBlur: 0,
      fromBrightness: .99, toBrightness: 1,
      fromSaturate: .99, toSaturate: 1,
      keepAnimation: 'none', clearFilter: true, clearTransform: true, clearOpacity: true,
    });
    animateFocus(document.getElementById('bubble-canvas'), {
      duration: 2050,
      fromOpacity: .56, toOpacity: 1,
      fromScale: 1.05, toScale: 1,
      fromBlur: 10, toBlur: 0,
      fromBrightness: .985, toBrightness: 1,
      fromSaturate: .99, toSaturate: 1,
      keepAnimation: 'none', clearFilter: true, clearTransform: true, clearOpacity: true,
    });
  }

  function runTitleLeadReveal(){}

  function runHeroRevealFocus(){}

  function dismissLoading(){
    const ld = document.getElementById('loading');
    if(ld && !ld._dismissed){
      ld._dismissed = true;
      document.body.classList.add('world-reveal');
      whaleFrontRevealStart=clk.elapsedTime;
      if(whaleModel){
        whaleModel.rotation.y=whaleFrontFaceYaw;
        whaleModel.rotation.z=0;
      }
      runWorldRevealFocus();

      ld.classList.add('hide');
      setTimeout(()=>{
        document.body.classList.remove('loading-phase');
      }, 120);
      setTimeout(()=>{
        document.body.classList.remove('hero-pending');
        document.body.classList.add('hero-reveal');

      }, 1000);
      setTimeout(()=>ld.remove(), 3200);
    }
  }

  function runLoadingAnim(){
    const binaryEl = document.getElementById('ld-binary');
    const numEl    = document.getElementById('ld-num');
    const hintEl   = document.getElementById('ld-hint');
    const subEl    = document.getElementById('ld-sub');
    const labelEl  = document.getElementById('ld-decode-label');
    const barEl    = document.querySelector('.ld-bar');
    if(!binaryEl || !numEl || !labelEl) return;

    const groups = Array.from(binaryEl.querySelectorAll('.bit-group'));
    const slots  = groups.map(g => g.querySelector('.slot-byte'));
    const milestoneYears = new Set([2001, 2008, 2015, 2020, 2026]);

    labelEl.style.opacity = '1';
    labelEl.textContent = 'DECODING ...';
    binaryEl.style.opacity = '1';
    binaryEl.style.transform = '';
    binaryEl.classList.remove('compact','celebrate','orange-shift');
    numEl.className = 'ld-num';
    numEl.innerHTML = '';
    numEl.textContent = '';
    hintEl.classList.remove('show');
    hintEl.textContent = '';
    subEl.classList.remove('show');
    subEl.textContent = '';
    if(barEl){
      barEl.classList.remove('run');
      barEl.style.width = '0%';
      void barEl.offsetWidth;
      requestAnimationFrame(()=> barEl.classList.add('run'));
    }

    const randTimer = setInterval(()=>{
      groups.forEach((g, i)=>{
        if(!g.dataset.locked){
          slots[i].textContent = randomByte();
        }
      });
    }, 72);

    function decodeGroup(index){
      const g = groups[index];
      if(!g) return;
      g.dataset.locked = '1';
      slots[index].textContent = g.dataset.byte || GROUPS[index].byte;
      g.classList.add('stopped');
      setTimeout(()=> g.classList.add('decoded'), 180);
    }

    function startYearCount(){
      labelEl.style.opacity = '1';
      labelEl.textContent = '1996 — 2026';
      numEl.className = 'ld-num show year-mode';
      const startYear = 1996;
      const endYear = 2026;
      const countDuration = 2000;
      let lastYear = startYear;
      numEl.textContent = startYear;

      const startAt = performance.now();

      const step = (now) => {
        const progress = Math.min(1, (now - startAt) / countDuration);
        const eased = easeOutCubic(progress);
        const year = Math.min(endYear, Math.round(startYear + (endYear - startYear) * eased));
        if(year !== lastYear){
          lastYear = year;
          numEl.textContent = year;
        }
        if(progress < 1){
          requestAnimationFrame(step);
          return;
        }
        numEl.textContent = endYear;
        setTimeout(()=>{
          const ld = document.getElementById('loading');
          numEl.classList.add('year-glow');
          setTimeout(()=>{
            numEl.classList.remove('year-glow');
            runYearBlast(numEl, ld);
          }, 220);
          setTimeout(()=>{
            labelEl.style.opacity = '0';
            setTimeout(dismissLoading, 420);
          }, 1760);
        }, 40);
      };

      requestAnimationFrame(step);
    }

    const kickoffs = [300, 800, 1300, 1800, 2300, 2820];
    kickoffs.forEach((t, i)=> setTimeout(()=> decodeGroup(i), t));

    const lastDecodedAt = kickoffs[kickoffs.length - 1] + 180;

    setTimeout(()=>{
      clearInterval(randTimer);
      binaryEl.classList.add('compact');
      binaryEl.classList.add('celebrate');
      labelEl.textContent = 'KUJIRA / DECODED';
      setTimeout(()=> binaryEl.classList.add('orange-shift'), 320);
      setTimeout(()=> binaryEl.classList.remove('celebrate'), 950);
    }, lastDecodedAt + 60);

    setTimeout(()=>{
      binaryEl.style.opacity = '0';
      binaryEl.style.transform = 'translateY(-14px) scale(.96)';
      startYearCount();
    }, lastDecodedAt + 1400);
  }

  if(document.readyState === 'loading'){
    document.addEventListener('DOMContentLoaded', runLoadingAnim);
  } else {
    runLoadingAnim();
  }

  window.addEventListener('load',()=>{
    setTimeout(dismissLoading, 16000);
  });
})();

