/* ══════════════════════════════════════════
   深海バブル（背景 Canvas 2D）
   ══════════════════════════════════════════ */
(function(){
  const bc  = document.getElementById('bubble-canvas');
  const bctx = bc.getContext('2d');

  /* --- キャンバスをウィンドウサイズに合わせる --- */
  function resizeBubbleCanvas(){
    bc.width  = window.innerWidth;
    bc.height = window.innerHeight;
  }
  resizeBubbleCanvas();
  window.addEventListener('resize', resizeBubbleCanvas);

  /* --- バブルのパラメータ定義 --- */
  const BUBBLE_COUNT = 28;

  function makeBubble(){
    const r   = 1.5 + Math.random() * 5.5;   // 半径 1.5〜7px
    return {
      x    : Math.random() * window.innerWidth,
      y    : window.innerHeight + r + Math.random() * window.innerHeight,
      r    : r,
      speed: 0.18 + Math.random() * 0.32,     // 非常にゆっくり（px/frame）
      wobAmp : (0.4 + Math.random() * 1.4) * r, // 左右ゆらぎ幅
      wobFreq: 0.003 + Math.random() * 0.006,  // 左右ゆらぎ周波数
      wobOff : Math.random() * Math.PI * 2,    // 位相オフセット
      alpha  : 0.04 + Math.random() * 0.09,   // 基本透明度（0.04〜0.13）
      // 色: ほぼ透明な水色〜白系
      hue    : 170 + Math.random() * 40,       // cyan〜blue-green
      phase  : Math.random() * Math.PI * 2,    // フレームカウンタオフセット
    };
  }

  const bubbles = [];
  for(let i = 0; i < BUBBLE_COUNT; i++){
    const b = makeBubble();
    // 初期配置: 画面内に均等にばらまく
    b.y = Math.random() * (window.innerHeight + 200) - 100;
    bubbles.push(b);
  }

  let frame = 0;

  function drawBubbles(){
    requestAnimationFrame(drawBubbles);
    frame++;

    bc.width = window.innerWidth;   // クリア（サイズ再設定でクリアされる）
    bc.height = window.innerHeight;

    const now = frame;

    for(let i = 0; i < bubbles.length; i++){
      const b = bubbles[i];

      /* 上昇 */
      b.y -= b.speed;

      /* 左右ゆらぎ */
      const wx = b.x + Math.sin(now * b.wobFreq + b.wobOff) * b.wobAmp;

      /* 画面上端を超えたらリセット */
      if(b.y < -b.r * 2){
        b.x     = Math.random() * window.innerWidth;
        b.y     = window.innerHeight + b.r;
        b.r     = 1.5 + Math.random() * 5.5;
        b.speed = 0.18 + Math.random() * 0.32;
        b.alpha = 0.04 + Math.random() * 0.09;
        b.wobAmp  = (0.4 + Math.random() * 1.4) * b.r;
        b.wobFreq = 0.003 + Math.random() * 0.006;
        b.wobOff  = Math.random() * Math.PI * 2;
        b.hue   = 170 + Math.random() * 40;
        continue;
      }

      /* 描画: グラデーション付き円 */
      const grad = bctx.createRadialGradient(
        wx - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1,  // ハイライト位置
        wx, b.y, b.r
      );
      const a = b.alpha;
      grad.addColorStop(0,   `hsla(${b.hue},80%,90%,${(a*1.8).toFixed(3)})`); // ハイライト
      grad.addColorStop(0.5, `hsla(${b.hue},70%,70%,${a.toFixed(3)})`);        // 本体
      grad.addColorStop(1,   `hsla(${b.hue},60%,50%,${(a*0.3).toFixed(3)})`);  // エッジ

      bctx.beginPath();
      bctx.arc(wx, b.y, b.r, 0, Math.PI * 2);
      bctx.fillStyle = grad;
      bctx.fill();

      /* リム（輪郭）: さらに薄く */
      bctx.beginPath();
      bctx.arc(wx, b.y, b.r, 0, Math.PI * 2);
      bctx.strokeStyle = `hsla(${b.hue},80%,85%,${(a*0.6).toFixed(3)})`;
      bctx.lineWidth   = 0.6;
      bctx.stroke();
    }
  }

  /* ロード後に開始 */
  window.addEventListener('load', drawBubbles);
})();


/* ══════════════════════════════════════════════════════
   深海花火エフェクト（クリックで発火）
   ══════════════════════════════════════════════════════ */
(function(){
  const fw   = document.getElementById('firework-canvas');
  const fctx = fw.getContext('2d');

  /* finale 30 に寄せた淡いレインボーパレット */
  const FW_PALETTE = ['#F6BED7','#F8CB90','#FFE78E','#DCEF9B','#9CDBF8','#B4A1F7','#F4B8D4'];
  function fwColor(offset = 0){
    const idx = (((_fwHue + offset) % FW_PALETTE.length) + FW_PALETTE.length) % FW_PALETTE.length;
    return FW_PALETTE[idx];
  }
  function fwStep(step = 1){
    _fwHue = (_fwHue + step) % FW_PALETTE.length;
  }
  /* 爆発ごとにずれる基準色相カウンター */
  let _fwHue = 0;

  let particles = [];
  let trails    = [];  // 打ち上げ軌跡
  let animId    = null;

  /* --- リサイズ --- */
  function resize(){
    fw.width  = window.innerWidth;
    fw.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  /* ─── パーティクルクラス ──────────────────────── */
  class Particle {
    constructor(x, y, color, angle, speed, type){
      this.x     = x;
      this.y     = y;
      this.color = color;
      this.angle = angle;
      this.speed = speed;
      this.vx    = Math.cos(angle) * speed;
      this.vy    = Math.sin(angle) * speed;
      this.alpha = 1.0;
      this.life  = 1.0;
      this.type  = type;   // 'spark'|'star'|'trail'|'ring'
      this.r     = type === 'star'   ? 3.5 + Math.random() * 2.5 :
                   type === 'ring'   ? 2.5 + Math.random() * 2.0 :
                   type === 'trail'  ? 1.8 + Math.random() * 1.8 :
                   type === 'willow' ? 2.2 + Math.random() * 1.8 :
                                       1.5 + Math.random() * 2.2;
      this.gravity   = type === 'ring'   ? 0.03 :
                       type === 'willow' ? 0.18 :
                       type === 'trail'  ? 0.05 : 0.10;
      this.friction  = type === 'ring'   ? 0.985 :
                       type === 'willow' ? 0.96  :
                       type === 'trail'  ? 0.92  : 0.945;
      this.decay     = type === 'trail'  ? 0.050 :
                       type === 'ring'   ? 0.018 :
                       type === 'willow' ? 0.013 : 0.013;
      /* 尾を引く spark の軌跡バッファ */
      this.tail = [];
      this.tailLen = type === 'star' || type === 'willow' ? 5 : 2;
    }
    update(){
      /* 尾バッファ更新 */
      this.tail.push({x:this.x, y:this.y, a:this.alpha});
      if(this.tail.length > this.tailLen) this.tail.shift();

      this.vx *= this.friction;
      this.vy  = this.vy * this.friction + this.gravity;
      this.x  += this.vx;
      this.y  += this.vy;
      this.life  -= this.decay;
      this.alpha  = Math.max(0, this.life);
      return this.life > 0;
    }
    draw(ctx){
      /* 尾を先に描画 */
      for(let i=0; i<this.tail.length; i++){
        const t  = this.tail[i];
        const ta = t.a * (i / this.tail.length) * 0.4;
        ctx.save();
        ctx.globalAlpha = ta;
        ctx.fillStyle   = this.color;
        const tr = this.r * (i / this.tail.length);
        ctx.beginPath();
        ctx.arc(t.x, t.y, Math.max(0.3, tr * 0.6), 0, Math.PI*2);
        ctx.fill();
        ctx.restore();
      }
      /* 本体 */
      ctx.save();
      ctx.globalAlpha   = this.alpha;
      ctx.shadowColor   = this.color;
      ctx.shadowBlur    = this.type === 'star' ? 7 : 3;
      ctx.fillStyle     = this.color;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.r, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    }
  }

  /* ─── 打ち上げ軌跡クラス ────────────────────── */
  class TrailDot {
    constructor(x, y, tx, ty, color){
      this.x = x; this.y = y;
      this.tx = tx; this.ty = ty;
      this.color = color;
      this.alpha = 0.7;
      this.r     = 1.5;
      this.decay = 0.08;
    }
    update(){ this.alpha -= this.decay; return this.alpha > 0; }
    draw(ctx){
      ctx.save();
      ctx.globalAlpha = this.alpha;
      ctx.fillStyle   = this.color;
      ctx.shadowColor = this.color;
      ctx.shadowBlur  = 4;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.r, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    }
  }

  /* ─── 爆発生成 ──────────────────────────────── */
  function explode(x, y){
    /* 爆発ごとにパレット位置をずらして最終30の色味へ寄せる */
    const baseIndex = _fwHue;
    const subIndex  = (_fwHue + 2) % FW_PALETTE.length;
    fwStep(1);

    /* 爆発タイプ（burst・willow 追加で豪華に） */
    const types = ['radial','ring','double','chrysanthemum','burst','willow','double','radial'];
    const etype = types[Math.floor(Math.random() * types.length)];

    if(etype === 'radial' || etype === 'double'){
      /* 放射状スパーク */
      const count = 50 + Math.floor(Math.random() * 25);
      for(let i=0; i<count; i++){
        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.12;
        const speed = 3.0 + Math.random() * 5.5;
        const colorIndex = baseIndex + Math.floor((i / count) * FW_PALETTE.length * 2) + (Math.random() < 0.18 ? 1 : 0);
        particles.push(new Particle(x, y, fwColor(colorIndex), angle, speed, 'spark'));
      }
      /* star 大粒子 */
      const stars = 10 + Math.floor(Math.random() * 5);
      for(let i=0; i<stars; i++){
        const angle = (i / stars) * Math.PI * 2;
        const speed = 1.8 + Math.random() * 3.5;
        const colorIndex = baseIndex + Math.floor((i / stars) * FW_PALETTE.length * 2);
        particles.push(new Particle(x, y, fwColor(colorIndex), angle, speed, 'star'));
      }
    }

    if(etype === 'ring' || etype === 'double'){
      /* 2重リング */
      for(let ring=0; ring<2; ring++){
        const count = 30 + Math.floor(Math.random() * 15);
        const spd   = 3.5 + ring * 1.8 + Math.random() * 1.5;
        for(let i=0; i<count; i++){
          const angle = (i / count) * Math.PI * 2;
          const colorIndex = subIndex + ring + Math.floor((i / count) * FW_PALETTE.length * 2);
          particles.push(new Particle(x, y, fwColor(colorIndex), angle, spd + Math.random()*0.5, 'ring'));
        }
      }
    }

    if(etype === 'chrysanthemum'){
      /* 菊花 */
      const count = 60;
      for(let i=0; i<count; i++){
        const angle = (i / count) * Math.PI * 2;
        const speed = (2.5 + Math.sin(i * 0.4) * 2.5) * (0.8 + Math.random() * 0.5);
        const colorIndex = baseIndex + Math.floor((i / count) * FW_PALETTE.length * 2);
        particles.push(new Particle(x, y, fwColor(colorIndex), angle, speed,
          Math.random() < 0.35 ? 'star' : 'spark'));
      }
    }

    if(etype === 'burst'){
      /* burst — 密集・全方向 */
      const count = 65 + Math.floor(Math.random() * 30);
      for(let i=0; i<count; i++){
        const angle = Math.random() * Math.PI * 2;
        const speed = 1.0 + Math.random() * 8.0;
        const colorIndex = baseIndex + Math.floor(Math.random() * FW_PALETTE.length);
        particles.push(new Particle(x, y, fwColor(colorIndex), angle, speed,
          Math.random() < 0.2 ? 'star' : 'spark'));
      }
      /* 外周リング */
      const rc = 30;
      for(let i=0; i<rc; i++){
        const angle = (i / rc) * Math.PI * 2;
        particles.push(new Particle(x, y, fwColor(baseIndex + i), angle, 6.0+Math.random()*1.5, 'ring'));
      }
    }

    if(etype === 'willow'){
      /* willow（柳） */
      const count = 40 + Math.floor(Math.random() * 20);
      for(let i=0; i<count; i++){
        const angle = (i / count) * Math.PI * 2 + Math.random() * 0.2;
        const speed = 2.5 + Math.random() * 5.0;
        const colorIndex = baseIndex + Math.floor((i / count) * FW_PALETTE.length * 2);
        particles.push(new Particle(x, y, fwColor(colorIndex), angle, speed, 'willow'));
      }
    }

    /* 中心フラッシュ */
    for(let i=0; i<3; i++)
      particles.push(new Particle(x, y, '#FFF8D9', Math.random()*Math.PI*2, Math.random()*1.5, 'star'));
  }

  /* 粒数キャップ：800粒超えたら古いものを一指切り削除 */
  function _capParticles(){
    if(particles.length > 600) particles.splice(0, particles.length - 600);
  }

  /* ─── アニメーションループ ──────────────────── */
  function loop(){
    animId = requestAnimationFrame(loop);

    /* 残像を標準の clearRect で消去（背景に塩塗りしない） */
    fctx.clearRect(0, 0, fw.width, fw.height);

    /* 毎フレームキャップ（重さ防止） */
    if(particles.length > 600) particles.splice(0, particles.length - 600);

    /* 軌跡描画 */
    trails = trails.filter(d=>{ const a=d.update(); if(a) d.draw(fctx); return a; });

    /* パーティクル描画 */
    particles = particles.filter(p=>{ const a=p.update(); if(a) p.draw(fctx); return a; });

    /* 何もなければループ停止 */
    if(particles.length === 0 && trails.length === 0){
      fctx.clearRect(0, 0, fw.width, fw.height);
      cancelAnimationFrame(animId);
      animId = null;
    }
  }

  /* ─── クリックイベント ──────────────────────── */
  document.addEventListener('click', e => {
    /* UIクリックは除外（ボタン等） */
    if(e.target.tagName === 'BUTTON' || e.target.tagName === 'A') return;

    const cx = e.clientX;
    const cy = e.clientY;

    /* 打ち上げ軌跡（画面下から打ち上げ演出は省略。クリック地点で即爆発） */
    /* 小さな前フラッシュ軌跡 */
    for(let i=0; i<8; i++){
      const angle  = Math.random() * Math.PI * 2;
      const dist   = Math.random() * 20;
      const color  = fwColor(i);
      trails.push(new TrailDot(
        cx + Math.cos(angle)*dist,
        cy + Math.sin(angle)*dist,
        cx, cy, color
      ));
    }

    /* 爆発 */
    explode(cx, cy);
    _capParticles();

    /* 多段爆発：最大3段、検席を絞った */
    const extraCount = Math.random() < 0.30 ? 2 : Math.random() < 0.60 ? 1 : 0;
    for(let e=0; e<extraCount; e++){
      setTimeout(()=>{
        const ox = cx + (Math.random()-0.5)*130;
        const oy = cy + (Math.random()-0.5)*130;
        explode(ox, oy);
        _capParticles();
      }, 100 + e*110 + Math.random()*80);
    }

    /* ループ起動 */
    if(!animId) loop();
  });

  /* ─── 最下部スクロールで自動花火 ──────────────── */
  (function(){
    let _fired = false;      // 一度発火したら再発火しない制御用フラグ
    let _canFire = false;    // ページロード後少し経ってから有効化

    // ページ読み込み直後の誤発火を防ぐため1秒後に有効化
    setTimeout(()=>{ _canFire = true; }, 1000);

    // ランダム座標にクリック花火と同じ処理で1発打ち上げ
    function launchOne(xRatio, yRatio){
      const cx = innerWidth  * xRatio;
      const cy = innerHeight * yRatio;
      // クリックと全く同じ: 軌跡 + 爆発 + 二段
      for(let i=0; i<8; i++){
        const angle = Math.random() * Math.PI * 2;
        const dist  = Math.random() * 20;
        const color = fwColor(i);
        trails.push(new TrailDot(
          cx + Math.cos(angle)*dist,
          cy + Math.sin(angle)*dist,
          cx, cy, color
        ));
      }
      explode(cx, cy);
      if(Math.random() < 0.5){
        setTimeout(()=>{
          explode(cx + (Math.random()-0.5)*80, cy + (Math.random()-0.5)*80);
        }, 120 + Math.random()*80);
      }
      if(!animId) loop();
    }

    // 複数発を時間差で打ち上げる（合計12発・画面全体をカバー）
    function launchFinale(){
      const shots = [
        [   0, 0.15, 0.28], [ 180, 0.85, 0.22], [ 340, 0.50, 0.18],
        [ 500, 0.25, 0.40], [ 660, 0.75, 0.30], [ 820, 0.40, 0.22],
        [ 980, 0.60, 0.35], [1140, 0.30, 0.45],
      ];
      shots.forEach(([delay, xr, yr]) => {
        setTimeout(() => launchOne(xr, yr), delay);
      });
    }

    // スクロール検知
    window.addEventListener('scroll', function onScroll(){
      if(!_canFire) return;
      if(_fired)   return;

      const scrolledPx  = scrollY;
      const maxScroll   = document.body.scrollHeight - innerHeight;
      // 最下部から30px以内に達したら発火
      if(maxScroll > 0 && scrolledPx >= maxScroll - 30){
        _fired = true;
        launchFinale();

        // 3秒後にリセット（再度一番下に来たらまた打ち上げ）
        setTimeout(()=>{ _fired = false; }, 3000);
      }
    }, { passive: true });
  })();

})();
